mapper.select:
select count(*)
from information_schema.tables
where table_schema = current_schema() and table_name = #{tableName}

select count(*)
from information_schema.columns
where table_schema = current_schema()
  and table_name = #{tableName}
  and column_name = #{columnName}

select count(*)
from pg_indexes
where schemaname = current_schema() and indexname = #{indexName}

select i.id,
       i.volume_id,
       i.fonds_code,
       i.fonds_name,
       i.category_code,
       i.category_name,
       i.archive_no,
       i.electronic_status,
       i.security_level_id,
       i.retention_period_id,
       i.department_id,
       i.archive_year,
       i.display_order,
       i.created_at,
       i.deleted_at,
       i.deleted_by,
       i.locked_flag,
       i.lock_reason,
       i.locked_by,
       i.locked_at
       ${selectColumns}
from am_archive_item i
join ${tableName} d on d.id = i.id
where i.deleted_flag = #{deleted}
  and d.deleted_flag = #{deleted}

    and #{userId} is not null


    and i.fonds_code = #{fondsCode}


    and (

        (

            i.fonds_code in

                #{dataScopeFondsCode}




                and




                        d.${condition.columnName} = #{condition.value}


                        d.${condition.columnName} in

                            #{conditionValue}



                        d.${condition.columnName} is null


                        d.${condition.columnName} is not null






                and

            i.security_level_id in

                #{dataScopeSecurityLevelId}




                and

            i.retention_period_id in

                #{dataScopeRetentionPeriodId}




                and

            i.department_id in

                #{dataScopeDepartmentId}



            false

        )

    )





                and d.${condition.columnName} = #{condition.value}


                and d.${condition.columnName} in

                    #{conditionValue}



                and d.${condition.columnName} like #{condition.value} escape '\'


                and d.${condition.columnName} like #{condition.value} escape '\'


                and d.${condition.columnName} >= #{condition.value}


                and d.${condition.columnName} <= #{condition.value}


                and d.${condition.columnName} >= #{condition.value}
                and d.${condition.columnName} <= #{condition.endValue}


                and d.${condition.columnName} is null


                and d.${condition.columnName} is not null


                and (d.${condition.columnName} is null or d.${condition.columnName} = '')


                and d.${condition.columnName} is not null and d.${condition.columnName} != ''






        and exists (
            select 1
            from am_archive_item_relation rel
            join am_archive_item ri on ri.deleted_flag = false
              and (
                  (#{group.directionName} = 'OUTGOING'
                   and rel.source_item_id = i.id
                   and ri.id = rel.target_item_id)
                  or (#{group.directionName} = 'INCOMING'
                      and rel.target_item_id = i.id
                      and ri.id = rel.source_item_id)
                  or (#{group.directionName} = 'BOTH'
                      and (
                          (rel.source_item_id = i.id and ri.id = rel.target_item_id)
                          or (rel.target_item_id = i.id and ri.id = rel.source_item_id)
                      ))
              )
            join ${group.tableName} rd on rd.id = ri.id
              and rd.deleted_flag = false
            where ri.category_code = #{group.categoryCode}




                            and rd.${condition.columnName} = #{condition.value}


                            and rd.${condition.columnName} like #{condition.value} escape '\'


                            and rd.${condition.columnName} like #{condition.value} escape '\'


                            and rd.${condition.columnName} >= #{condition.value}


                            and rd.${condition.columnName} <= #{condition.value}


                            and rd.${condition.columnName} >= #{condition.value}
                            and rd.${condition.columnName} <= #{condition.endValue}


                            and (rd.${condition.columnName} is null or rd.${condition.columnName} = '')


                            and rd.${condition.columnName} is not null and rd.${condition.columnName} != ''




        )



    and exists (
        select 1
        from am_archive_item_search s
        where s.archive_item_id = i.id
          and (
              s.search_text ilike '%' || replace(replace(#{fullTextKeyword}, '%', '\%'), '_', '\_') || '%' escape '\'
              or s.search_text % #{fullTextKeyword}
          )
    )


    and (${cursorPredicateSql})

order by ${orderBySql}
limit #{limit}

select count(1)
from am_archive_item
where deleted_flag = false
  and category_code = #{categoryCode}
  and archive_no = #{archiveNo}

  and id != #{excludedId}

mapper.update:
update ${tableName}
set

    ${assignment.columnName} = #{assignment.value}

    , updated_at = localtimestamp
where id = #{id} and deleted_flag = false

mapper.select:
select *
from ${tableName}
where id = #{id} and deleted_flag = false

select id, fonds_code, fonds_name, category_code, category_name, archive_no, electronic_status, security_level_id, retention_period_id, archive_year, locked_flag, lock_reason, locked_by, locked_at from am_archive_volume where deleted_flag = false
and fonds_code = #{fondsCode}
and category_code = #{categoryCode}
order by sort_order, id desc

select count(1)
from am_archive_volume
where deleted_flag = false
  and category_code = #{categoryCode}
  and archive_no = #{archiveNo}

  and id != #{excludedId}

mapper.delete:
delete from am_archive_item_electronic_file
where archive_item_id = #{archiveItemId}
  and id = #{electronicFileId}

mapper.select:
select storage_object_id
from am_archive_item_electronic_file
where archive_item_id = #{archiveItemId}
  and id = #{electronicFileId}

mapper.delete:
delete from am_archive_item_relation
where id = #{id}
  and source_item_id = #{sourceItemId}

mapper.select:
select *
from ${tableName}
where item_id = #{itemId}
  and deleted_flag = false
order by line_order, id
